import { type MouseEvent } from 'react';

import { useTooltip } from '../components/overlay-tooltip/contexts/TooltipContext.js';
import type { Data, Overlay } from '../components/overlay-tooltip/types.js';
import { useTooltipActions } from '../components/overlay-tooltip/useTooltipActions.js';

type Options = {
  onToolbarVisibilityChange: (visible: boolean) => void;
  getTooltipData: (event: MouseEvent<HTMLDivElement>) => Data | undefined;
};

export const useOverlayEventHandlers = (overlay: Overlay, options: Options) => {
  const overlayRef = overlay.overlayRef;
  const tooltipStore = useTooltip();
  const { hover, pin, unpin, outOfBounds } = useTooltipActions();
  const { onToolbarVisibilityChange, getTooltipData } = options;

  const handlePointerEnter = () => {
    onToolbarVisibilityChange(true);
  };

  const handlePointerMove = (event: MouseEvent<HTMLDivElement>) => {
    if (
      !overlayRef.current ||
      tooltipStore.getState().pinned ||
      event.target !== overlayRef.current
    ) {
      return;
    }

    const tooltipData = getTooltipData(event);
    if (tooltipData) {
      hover(event.nativeEvent, tooltipData);
    } else {
      outOfBounds();
    }
  };

  const handlePointerLeave = () => {
    onToolbarVisibilityChange(false);
    outOfBounds();
  };

  const handleMouseClick = (event: MouseEvent<HTMLDivElement>) => {
    event.stopPropagation();

    if (!overlayRef.current || event.target !== overlayRef.current) {
      return;
    }

    const inBounds = tooltipStore.getState().inBounds;
    const tooltipData = getTooltipData(event);
    const isPinned = tooltipStore.getState().pinned;

    if (inBounds || isPinned) {
      if (isPinned) {
        unpin();
        if (tooltipData) {
          hover(event.nativeEvent, tooltipData);
        }
      } else if (tooltipData) {
        pin(event.nativeEvent, tooltipData);
      }
    }
  };

  return {
    handlePointerEnter,
    handlePointerMove,
    handlePointerLeave,
    handleMouseClick,
  };
};
